'use client';

import { AdminShell } from '@/components/AdminShell';
import { RequireAuth } from '@/components/RequireAuth';
import { adminApi } from '@/lib/api';
import { useEffect, useState } from 'react';

export default function TablesPage() {
  const [items, setItems] = useState<any[]>([]);
  const [tableCode, setTableCode] = useState('A2');
  const [tableName, setTableName] = useState('Table A2');
  const [isActive, setIsActive] = useState(true);
  const [error, setError] = useState('');
  const [query, setQuery] = useState('');

  async function load() {
    try {
      const r = await adminApi.tables();
      setItems(r.items);
    } catch (e: any) {
      setError(e.message || 'Gagal load tables');
    }
  }

  useEffect(() => { load(); }, []);

  const filtered = items.filter((t) => {
    if (!query) return true;
    const q = query.toLowerCase();
    return String(t.table_code || '').toLowerCase().includes(q) || String(t.table_name || '').toLowerCase().includes(q);
  });

  return (
    <RequireAuth>
      <AdminShell
        title="Tables"
        subtitle="Kelola meja dan QR order"
        actions={<button className="btn" onClick={load}>Refresh</button>}
      >
        <div className="grid2">
          <div className="card">
            <h3>Tambah / Update Meja</h3>
            <div className="grid2">
              <input value={tableCode} onChange={(e) => setTableCode(e.target.value)} placeholder="Code" />
              <input value={tableName} onChange={(e) => setTableName(e.target.value)} placeholder="Name" />
            </div>
            <div style={{ marginTop: 10 }} className="grid2">
              <label className="small">
                <input
                  type="checkbox"
                  checked={isActive}
                  onChange={(e) => setIsActive(e.target.checked)}
                  style={{ width: 16, height: 16, marginRight: 8 }}
                />
                Aktif
              </label>
              <button
                className="btn"
                onClick={async () => {
                  await adminApi.upsertTable({ table_code: tableCode, table_name: tableName, is_active: isActive, rotate_qr: true });
                  await load();
                }}
              >
                Save + Rotate QR
              </button>
            </div>
            <p className="small">Rotasi QR akan menonaktifkan token lama.</p>
            {error ? <div className="small">{error}</div> : null}
          </div>
          <div className="card">
            <h3>Cari Meja</h3>
            <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Cari kode / nama meja" />
            <div style={{ height: 10 }} />
            <div className="small">Total: {filtered.length} meja</div>
          </div>
        </div>
        <div className="card">
          <table className="table">
            <thead>
              <tr>
                <th>Kode</th>
                <th>Nama</th>
                <th>Status</th>
                <th>QR Token</th>
                <th>Aksi</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((t) => (
                <tr key={t.id}>
                  <td><b>{t.table_code}</b></td>
                  <td>{t.table_name}</td>
                  <td>
                    <span className={t.is_active ? 'pill success' : 'pill danger'}>
                      {t.is_active ? 'Active' : 'Inactive'}
                    </span>
                  </td>
                  <td className="small">{t.qr_token}</td>
                  <td>
                    <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                      <button
                        className="btn outline"
                        onClick={async () => {
                          await adminApi.upsertTable({ table_code: t.table_code, table_name: t.table_name, is_active: t.is_active, rotate_qr: true });
                          await load();
                        }}
                      >
                        Rotate QR
                      </button>
                      <button
                        className="btn ghost"
                        onClick={async () => {
                          await adminApi.upsertTable({ table_code: t.table_code, table_name: t.table_name, is_active: !t.is_active });
                          await load();
                        }}
                      >
                        {t.is_active ? 'Deactivate' : 'Activate'}
                      </button>
                      <button
                        className="btn outline"
                        onClick={async () => {
                          if (navigator?.clipboard) await navigator.clipboard.writeText(String(t.qr_token || ''));
                        }}
                      >
                        Copy Token
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </AdminShell>
    </RequireAuth>
  );
}
